<div class="wrap sc-library-planning-admin sc-library-release-admin">
    <div class="sc-library-planning-admin__head"><div><p class="sc-library-planning-eyebrow"><?php esc_html_e('Sustainable Catalyst Library', 'sustainable-catalyst-library'); ?></p><h1><?php esc_html_e('Release Coordination', 'sustainable-catalyst-library'); ?></h1><p><?php esc_html_e('Coordinate release windows, workload, milestones, blockers, and dependencies without automatically scheduling WordPress posts.', 'sustainable-catalyst-library'); ?></p></div><div class="sc-library-planning-admin__actions"><a class="button" href="<?php echo esc_url(admin_url('admin.php?page=sc-library-planning-analytics')); ?>"><?php esc_html_e('Planning analytics', 'sustainable-catalyst-library'); ?></a><button type="button" class="button" onclick="window.print()"><?php esc_html_e('Print roadmap', 'sustainable-catalyst-library'); ?></button></div></div>
    <form method="post" action="options.php" class="card sc-library-release-settings"><?php settings_fields('sc_library_release_coordination'); ?><h2><?php esc_html_e('Coordination settings', 'sustainable-catalyst-library'); ?></h2><div class="sc-library-admin-grid"><label><span><?php esc_html_e('Capacity threshold per release window', 'sustainable-catalyst-library'); ?></span><input type="number" step="0.25" min="0" name="sc_library_release_capacity_threshold" value="<?php echo esc_attr((string) get_option('sc_library_release_capacity_threshold', 40)); ?>"></label><label><span><?php esc_html_e('Default effort unit', 'sustainable-catalyst-library'); ?></span><select name="sc_library_default_effort_unit"><?php foreach (SC_Library_Planning_Analytics::effort_units() as $value => $label) : ?><option value="<?php echo esc_attr($value); ?>" <?php selected(get_option('sc_library_default_effort_unit', 'points'), $value); ?>><?php echo esc_html($label); ?></option><?php endforeach; ?></select></label><label><span><?php esc_html_e('On-time tolerance, days', 'sustainable-catalyst-library'); ?></span><input type="number" min="0" max="365" name="sc_library_on_time_tolerance_days" value="<?php echo esc_attr((string) get_option('sc_library_on_time_tolerance_days', 7)); ?>"></label></div><?php submit_button(__('Save coordination settings', 'sustainable-catalyst-library')); ?></form>
    <section class="sc-library-planning-metrics"><?php foreach ($release['summary'] as $key => $value) : ?><div class="sc-library-planning-metric"><span><?php echo esc_html(ucwords(str_replace('_', ' ', $key))); ?></span><strong><?php echo esc_html((string) $value); ?></strong></div><?php endforeach; ?></section>
    <section class="sc-library-dependency-graph card"><h2><?php esc_html_e('Dependency graph', 'sustainable-catalyst-library'); ?></h2><p><?php esc_html_e('Lines point from a planned record to the record it depends on. Unresolved edges are highlighted.', 'sustainable-catalyst-library'); ?></p><div data-sc-dependency-graph></div><script type="application/json" data-sc-dependency-data><?php echo wp_json_encode($graph, JSON_UNESCAPED_SLASHES | JSON_HEX_TAG); ?></script></section>
    <section class="sc-library-release-windows"><h2><?php esc_html_e('Release windows', 'sustainable-catalyst-library'); ?></h2><?php foreach ($release['windows'] as $window) : ?><details class="sc-library-release-window<?php echo $window['over_capacity'] ? ' is-over-capacity' : ''; ?>" <?php echo ($window['blocked'] || $window['overdue'] || $window['over_capacity']) ? 'open' : ''; ?>><summary><span><strong><?php echo esc_html($window['label']); ?></strong><small><?php echo esc_html(sprintf(__('%1$d records · %2$s effort', 'sustainable-catalyst-library'), $window['count'], $window['effort_display'])); ?></small></span><span class="sc-library-release-window__signals"><?php if ($window['blocked']) : ?><b><?php echo esc_html(sprintf(__('%d blocked', 'sustainable-catalyst-library'), $window['blocked'])); ?></b><?php endif; ?><?php if ($window['overdue']) : ?><b><?php echo esc_html(sprintf(__('%d overdue', 'sustainable-catalyst-library'), $window['overdue'])); ?></b><?php endif; ?><?php if ($window['over_capacity']) : ?><b><?php esc_html_e('Over capacity', 'sustainable-catalyst-library'); ?></b><?php endif; ?></span></summary><table class="widefat striped"><thead><tr><th><?php esc_html_e('Plan', 'sustainable-catalyst-library'); ?></th><th><?php esc_html_e('Status', 'sustainable-catalyst-library'); ?></th><th><?php esc_html_e('Progress', 'sustainable-catalyst-library'); ?></th><th><?php esc_html_e('Effort', 'sustainable-catalyst-library'); ?></th><th><?php esc_html_e('Owner', 'sustainable-catalyst-library'); ?></th><th><?php esc_html_e('Blocker', 'sustainable-catalyst-library'); ?></th></tr></thead><tbody><?php foreach ($window['plans'] as $plan) : ?><tr><td><a href="<?php echo esc_url($plan['url']); ?>"><?php echo esc_html($plan['title']); ?></a></td><td><?php echo esc_html($plan['status']); ?></td><td><?php echo esc_html((string) $plan['progress']); ?>%</td><td><?php echo esc_html((string) $plan['effort']); ?></td><td><?php echo esc_html($plan['owner'] ?: '—'); ?></td><td><?php echo $plan['blocked'] ? esc_html__('Blocked', 'sustainable-catalyst-library') : '—'; ?></td></tr><?php endforeach; ?></tbody></table></details><?php endforeach; ?></section>
</div>
